const e=JSON.parse('{"key":"v-92191dce","path":"/vue/%E5%89%8D%E7%AB%AF%E8%B7%AF%E7%94%B1.html","title":"vue解读源码之前端路由","lang":"zh-CN","frontmatter":{"title":"vue解读源码之前端路由","isTimeLine":true,"date":"2025-09-29T00:00:00.000Z","category":["前端"],"tag":["Vue","源码"]},"headers":[{"level":3,"title":"SPA是什么","slug":"spa是什么","link":"#spa是什么","children":[]},{"level":3,"title":"为什么要有前端路由？","slug":"为什么要有前端路由","link":"#为什么要有前端路由","children":[]},{"level":3,"title":"hash模式","slug":"hash模式","link":"#hash模式","children":[]},{"level":3,"title":"history模式","slug":"history模式","link":"#history模式","children":[]},{"level":3,"title":"两者模式比较","slug":"两者模式比较","link":"#两者模式比较","children":[]},{"level":3,"title":"链接","slug":"链接","link":"#链接","children":[]}],"git":{"createdTime":1773506313000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":3.88,"words":1165},"filePathRelative":"vue/前端路由.md","localizedDate":"2025年9月29日","excerpt":"<h3> SPA是什么</h3>\\n<ol>\\n<li>SPA(single page web application),单页Web应用,简单来说就是一个web项目只有一个HTML页面，一旦页面加载完成，就不会因为用户的操作而进行页面的重新加载或跳转，而是利用 JS 动态的变换 HTML 的内容来模拟多个视图间跳转。所以SPA允许在不刷新页面的情况下更改URL并渲染不同内容。</li>\\n<li>旧的网站是每个HTML文件都是一个完成的HTML页面，而在SPA 的应用设计中，一个应用只有一个HTML文件。</li>\\n<li>SPA 的出现大大提高了 WEB 应用的交互体验，但是SPA是通过 JS 改变 HTML 内容来实现的，页面本身的 url 并没有变化，这样会导致刷新、前进还是后退无法被浏览器记录；并且只有一个 url，对 SEO 不友好。</li>\\n</ol>"}');export{e as data};
